// Payload: { nome_cliente, nicho, handle_cliente, concorrentes: ['@c1','@c2'] }
const raw  = $input.first().json;
const body = raw.body ?? raw;

const nome_cliente   = (body.nome_cliente   || '').trim();
const nicho          = (body.nicho          || '').trim();
const handle_cliente = (body.handle_cliente || '').replace('@','').trim();
const concorrentes   = (body.concorrentes   || [])
  .map(h => String(h).replace('@','').trim())
  .filter(Boolean);

if (!nome_cliente || !nicho || !handle_cliente || concorrentes.length === 0) {
  throw new Error('Payload incompleto. Envie: nome_cliente, nicho, handle_cliente, concorrentes[].');
}

const todos_handles = [handle_cliente, ...concorrentes];

return [{ json: {
  nome_cliente,
  nicho,
  handle_cliente,
  concorrentes,
  todos_handles,
  iniciado_em: new Date().toISOString(),
}}];

// Transforma 1 item com array todos_handles em N itens (1 por handle)
// Cada item carrega o contexto completo + handle atual + tipo (cliente/concorrente)
const data = $input.first().json;

if (!Array.isArray(data.todos_handles) || data.todos_handles.length === 0) {
  throw new Error('todos_handles ausente ou vazio.');
}

return data.todos_handles.map(handle => ({
  json: {
    // Contexto da auditoria
    nome_cliente:   data.nome_cliente,
    nicho:          data.nicho,
    handle_cliente: data.handle_cliente,
    concorrentes:   data.concorrentes,
    todos_handles:  data.todos_handles,
    iniciado_em:    data.iniciado_em,
    // Handle atual e seu papel
    handle: handle,
    tipo:   handle === data.handle_cliente ? 'cliente' : 'concorrente',
  }
}));

// Combina resposta RapidAPI (índice i) com o handle/tipo original (Expandir Handles índice i)
const rapItems  = $input.all();
const origItems = $('Expandir Handles').all();

function normalizarPosts(rawItems) {
  return (rawItems || []).slice(0, 20).map(node => {
    const legenda     = (node.edge_media_to_caption?.edges?.[0]?.node?.text ?? node.caption ?? '').slice(0, 600);
    const curtidas    = node.edge_liked_by?.count         ?? node.like_count     ?? 0;
    const comentarios = node.edge_media_to_comment?.count ?? node.comment_count  ?? 0;
    const is_video    = node.is_video ?? (node.media_type === 2);
    const engajamento = curtidas + comentarios;
    return {
      shortCode:     node.shortcode ?? node.code ?? '',
      url:           `https://www.instagram.com/p/${node.shortcode ?? node.code ?? ''}/`,
      legenda,
      curtidas,
      comentarios,
      visualizacoes: node.video_view_count ?? 0,
      tipo:          is_video ? 'video' : (node.edge_sidecar_to_children ? 'carrossel' : 'foto'),
      videoUrl:      node.video_url    ?? null,
      thumbnailUrl:  node.display_url  ?? node.thumbnail_url ?? null,
      data:          node.taken_at_timestamp
                       ? new Date(node.taken_at_timestamp * 1000).toISOString()
                       : null,
      engajamento,
    };
  });
}

return rapItems.map((rapItem, idx) => {
  const orig = origItems[idx]?.json || {};
  const resp = rapItem.json;

  // Suporta múltiplas estruturas de resposta do Instagram120
  const u = resp.user ?? resp.data?.user ?? {};
  const rawItems =
    resp.items ??
    resp.data?.items ??
    (u.edge_owner_to_timeline_media?.edges || []).map(e => e.node) ??
    [];

  const posts          = normalizarPosts(rawItems);
  const seguidores     = u.edge_followed_by?.count ?? u.follower_count  ?? 0;
  const seguindo       = u.edge_follow?.count       ?? u.following_count ?? 0;
  const total_posts    = u.edge_owner_to_timeline_media?.count ?? u.media_count ?? 0;
  const totalEng       = posts.reduce((s, x) => s + x.engajamento, 0);
  const taxa_engajamento = posts.length
    ? ((totalEng / posts.length / (seguidores || 1)) * 100).toFixed(2)
    : '0.00';
  const media_curtidas    = posts.length ? Math.round(posts.reduce((s, x) => s + x.curtidas,    0) / posts.length) : 0;
  const media_comentarios = posts.length ? Math.round(posts.reduce((s, x) => s + x.comentarios, 0) / posts.length) : 0;

  // Mix de formatos
  const total = posts.length || 1;
  const qtdVideo    = posts.filter(p => p.tipo === 'video').length;
  const qtdCarrossel= posts.filter(p => p.tipo === 'carrossel').length;
  const qtdFoto     = posts.filter(p => p.tipo === 'foto').length;

  return { json: {
    // Contexto
    handle:         orig.handle,
    tipo:           orig.tipo,
    nome_cliente:   orig.nome_cliente,
    nicho:          orig.nicho,
    handle_cliente: orig.handle_cliente,
    concorrentes:   orig.concorrentes,
    todos_handles:  orig.todos_handles,
    // Dados do perfil
    bio:              u.biography ?? u.bio ?? '',
    seguidores,
    seguindo,
    total_posts,
    verificado:       u.is_verified ?? false,
    link_externo:     u.external_url ?? '',
    taxa_engajamento,
    media_curtidas,
    media_comentarios,
    mix_formatos: {
      reels_pct:     Math.round((qtdVideo    / total) * 100),
      carrossel_pct: Math.round((qtdCarrossel/ total) * 100),
      foto_pct:      Math.round((qtdFoto     / total) * 100),
    },
    posts,
    top_posts:        [...posts].sort((a, b) => b.engajamento - a.engajamento).slice(0, 5),
    posts_video:      posts.filter(x => x.tipo === 'video' && x.videoUrl),
    ultimos_15_posts: posts.slice(0, 15),
  }};
});

// Agrupa perfis separando o cliente dos concorrentes
const perfis = $input.first().json.perfis || [];

const cliente_dados      = perfis.find(p => p.tipo === 'cliente') || null;
const concorrentes_dados = perfis.filter(p => p.tipo === 'concorrente');

if (!cliente_dados) {
  throw new Error('Perfil do cliente não encontrado. Verifique se o handle_cliente retornou dados da RapidAPI.');
}

// Resumo comparativo rápido
const melhor_concorrente = concorrentes_dados.reduce((best, c) => {
  return parseFloat(c.taxa_engajamento) > parseFloat(best?.taxa_engajamento || '0') ? c : best;
}, null);

const gap_engajamento = melhor_concorrente
  ? (parseFloat(melhor_concorrente.taxa_engajamento) - parseFloat(cliente_dados.taxa_engajamento)).toFixed(2)
  : '0.00';

return [{ json: {
  // Metadados da auditoria
  nome_cliente:    cliente_dados.nome_cliente,
  nicho:           cliente_dados.nicho,
  handle_cliente:  cliente_dados.handle_cliente,
  concorrentes:    cliente_dados.concorrentes,
  todos_handles:   cliente_dados.todos_handles,
  iniciado_em:     new Date().toISOString(),
  // Perfis separados
  cliente_dados,
  concorrentes_dados,
  total_perfis: perfis.length,
  // Diagnóstico rápido
  melhor_concorrente_handle: melhor_concorrente?.handle || null,
  gap_engajamento_pct: gap_engajamento,
}}];

// Consolida todos os dados coletados e identifica os top 3 vídeos virais dos concorrentes
const base   = $('Separar Cliente e Concorrentes').first().json;
const tendRaw= $('Serper — Tendências do Nicho').first().json;
const kwRaw  = $('Serper — Keywords do Nicho').first().json;
const adsRaw = $('Apify — Facebook Ads Library').first().json;

const tendencias_google = (tendRaw.organic || []).slice(0, 8).map(r => ({
  titulo:  r.title,
  snippet: r.snippet,
  link:    r.link,
}));

const keywords_google = (kwRaw.organic || []).slice(0, 8).map(r => ({
  titulo:  r.title,
  snippet: r.snippet,
}));

const anuncios_facebook = (Array.isArray(adsRaw) ? adsRaw : []).slice(0, 15).map(ad => ({
  page_name:   ad.pageName            || ad.page_name          || '',
  titulo:      ad.title               || ad.ad_creative_body   || '',
  cta:         ad.cta_text            || ad.call_to_action_type|| '',
  status:      ad.is_active ? 'ativo' : 'inativo',
  formato:     ad.ad_type             || '',
  url_destino: ad.snapshot_url        || '',
}));

// Coleta todos os vídeos dos concorrentes ordenados por engajamento
const allVideos = [];
(base.concorrentes_dados || []).forEach(conc => {
  (conc.posts_video || []).forEach(post => {
    if (post.videoUrl) {
      allVideos.push({
        ...post,
        handle_concorrente: conc.handle,
        seguidores_conc:    conc.seguidores,
        taxa_eng_perfil:    conc.taxa_engajamento,
      });
    }
  });
});
allVideos.sort((a, b) => b.engajamento - a.engajamento);
const top3 = allVideos.slice(0, 3);

const mergedBase = {
  ...base,
  tendencias_google,
  keywords_google,
  anuncios_facebook,
};

// Sem vídeos: retorna 1 item com flag — Whisper será pulado pelo IF
if (top3.length === 0) {
  return [{ json: { ...mergedBase, video_atual: null, sem_videos: true, top_virais: [] } }];
}

// 1 item por vídeo viral → Download + Whisper roda uma vez para cada
return top3.map((video, idx) => ({
  json: {
    ...mergedBase,
    video_atual:  video,
    video_index:  idx,
    sem_videos:   false,
    top_virais:   top3,
  }
}));

// Combina transcrição do Whisper com metadados do vídeo (via paired items)
const whisperItems  = $input.all();
const videoItems    = $('Enriquecer Dados + Identificar Vídeos Virais').all();

return whisperItems.map((item, idx) => {
  const video = videoItems[idx]?.json?.video_atual || {};
  return { json: {
    transcricao:         item.json.text || '[sem transcrição]',
    handle_concorrente:  video.handle_concorrente || '',
    legenda:             video.legenda            || '',
    curtidas:            video.curtidas           || 0,
    comentarios:         video.comentarios        || 0,
    engajamento:         video.engajamento        || 0,
    video_index:         idx,
  }};
});

// Caminho alternativo: sem vídeos para transcrever
const item = $input.first().json;

const base = $('Separar Cliente e Concorrentes').first().json;
const tendencias = $('Serper — Tendências do Nicho').first().json;
const keywords   = $('Serper — Keywords do Nicho').first().json;
const adsRaw     = $('Apify — Facebook Ads Library').first().json;

const tendencias_google = (tendencias.organic || []).slice(0, 8).map(r => ({ titulo: r.title, snippet: r.snippet, link: r.link }));
const keywords_google   = (keywords.organic   || []).slice(0, 8).map(r => ({ titulo: r.title, snippet: r.snippet }));
const anuncios_facebook = (Array.isArray(adsRaw) ? adsRaw : []).slice(0, 15).map(ad => ({
  page_name: ad.pageName || ad.page_name || '',
  titulo:    ad.title || ad.ad_creative_body || '',
  cta:       ad.cta_text || ad.call_to_action_type || '',
  formato:   ad.ad_type || '',
}));

const c = base.cliente_dados || {};
const cliente_resumo = {
  nome:              base.nome_cliente,
  nicho:             base.nicho,
  handle:            `@${base.handle_cliente}`,
  bio:               c.bio               || '',
  seguidores:        c.seguidores         || 0,
  taxa_engajamento:  `${c.taxa_engajamento || '0.00'}%`,
  media_curtidas:    c.media_curtidas     || 0,
  media_comentarios: c.media_comentarios  || 0,
  mix_formatos:      c.mix_formatos       || {},
  top_5_posts:       (c.top_posts || []).map(p => ({ legenda: p.legenda, curtidas: p.curtidas, comentarios: p.comentarios, tipo: p.tipo })),
  ultimos_15_posts:  (c.ultimos_15_posts || []).map(p => ({ legenda: p.legenda, curtidas: p.curtidas, comentarios: p.comentarios, tipo: p.tipo })),
};

const concorrentes_resumo = (base.concorrentes_dados || []).map(cc => ({
  handle:            `@${cc.handle}`,
  bio:               cc.bio,
  seguidores:        cc.seguidores,
  taxa_engajamento:  `${cc.taxa_engajamento}%`,
  media_curtidas:    cc.media_curtidas,
  mix_formatos:      cc.mix_formatos || {},
  top_5_posts:       (cc.top_posts || []).map(p => ({ legenda: p.legenda, curtidas: p.curtidas, comentarios: p.comentarios, tipo: p.tipo })),
}));

const userContent = JSON.stringify({
  cliente:                   cliente_resumo,
  concorrentes:              concorrentes_resumo,
  videos_virais_transcritos: [],
  tendencias_google,
  palavras_chave:            keywords_google,
  anuncios_ativos:           anuncios_facebook,
}, null, 2);

const systemPrompt = `Você é um Growth Hacker Sênior com 12 anos de experiência em marketing digital no Brasil. MISSÃO: Produzir um DOSSIÊ DE AUDITORIA COMPETITIVA baseado EXCLUSIVAMENTE nos dados do JSON. Nunca seja genérico. Cite dados. Se ausente: [dado não disponível]. Gere os 6 módulos completos em Markdown. Mínimo 3.000 palavras. Comece pelo Módulo 1 sem introduções. Termine com: 📋 FIM DO DOSSIÊ — Gerado em ${new Date().toLocaleDateString('pt-BR')}`;

return [{ json: {
  nome_cliente:       base.nome_cliente,
  nicho:              base.nicho,
  handle_cliente:     base.handle_cliente,
  cliente_dados:      base.cliente_dados,
  concorrentes_dados: base.concorrentes_dados,
  tendencias_google,
  keywords_google,
  anuncios_facebook,
  videos_transcritos: [],
  gap_engajamento_pct: base.gap_engajamento_pct,
  gpt_payload: {
    model:       'gpt-4o',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user',   content: userContent  },
    ],
    max_tokens:  8000,
    temperature: 0.72,
  },
}}];

const gptResponse = $input.first().json;
const baseData    = $('Unir Caminhos GPT').first().json;

const dossie_markdown = gptResponse?.choices?.[0]?.message?.content || '[Erro: GPT-4o não retornou conteúdo]';
const tokens_usados   = gptResponse?.usage?.total_tokens || 0;
const titulo          = `Dossiê Auditoria IA — ${baseData.nome_cliente} | ${baseData.nicho} | ${new Date().toLocaleDateString('pt-BR')}`;

return [{ json: {
  ...baseData,
  dossie_markdown,
  titulo_documento: titulo,
  tokens_usados,
  gerado_em: new Date().toISOString(),
}}];

const base       = $('Formatar Dossiê').first().json;
const docCreated = $('Google Docs — Criar Documento').first().json;
const docId      = docCreated.documentId || '';

return [{ json: {
  sucesso:                 true,
  cliente:                 base.nome_cliente,
  nicho:                   base.nicho,
  handle_cliente:          `@${base.handle_cliente}`,
  concorrentes_analisados: (base.concorrentes_dados || []).map(c => `@${c.handle}`),
  total_perfis_analisados: base.total_perfis || 0,
  gap_engajamento_pct:     base.gap_engajamento_pct || '0.00',
  melhor_concorrente:      base.melhor_concorrente_handle ? `@${base.melhor_concorrente_handle}` : null,
  videos_transcritos:      (base.videos_transcritos || []).length,
  tokens_usados:           base.tokens_usados,
  gerado_em:               base.gerado_em,
  documento: {
    titulo:      base.titulo_documento,
    id:          docId,
    link_editar: docId ? `https://docs.google.com/document/d/${docId}/edit`      : null,
    link_pdf:    docId ? `https://docs.google.com/document/d/${docId}/export?format=pdf` : null,
  },
}}];
